def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    for c in range(1, b + 3):
                        val = ((ratio - a) ** 6) / (a * b * c + 1)
                        term = val * np.sin(ratio * (b + c) / (a + 2))
                        priority += term * np.tanh(ratio / (c + 0.5))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.15)) ** 2.1
            if bin_cap < item * 0.5:
                priority += np.sqrt(item * bin_cap) * 7.2
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    val = ((ratio - p) ** 4) * np.cos(ratio * q) / (q + 0.8)
                    priority += np.tanh(val) * 1.6
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3.5
            if bin_cap > item * 3:
                priority -= np.exp(-ratio) * 5
        elif 3 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 3) ** r) / (r * 2.2) * np.sin(r * ratio * 1.5)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (5 - ratio)) * 2.2
            if (i * int(item * 2)) % 5 == 0:
                priority *= 1.4
        elif 1 <= ratio < 3:
            s = 0
            for n in range(1, 20):
                s += ((3 - ratio) ** n) / (n ** 2 + 1)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.8 / (ratio + 0.07))
            for m in range(1, 8):
                priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for x in range(1, 18):
                s += ((1 - ratio) ** x) / (x * 5)
            if (i + int(item * 2.2)) % 5 == 0:
                s *= np.log1p(bin_cap + 5) * 1.7
            else:
                s /= (np.sqrt(bin_cap + 3) + 2.5)
            priority = s
            for y in range(1, 9):
                priority += ((1 - ratio) ** y) * np.sin(y * item * 1.7) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 3)
            priority = s + 2 / (bin_cap + 5)
            if int(item * 1.6) % 6 == 0:
                priority *= 3
            else:
                priority /= 2.8
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.4)
        elif 0 < ratio < 0.2:
            s = 0
            for t in range(1, 13):
                s += ((0.2 - ratio) ** t) / (t * 8) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 7 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.9)
        else:
            priority = np.tanh(ratio) * 10 - np.log1p(bin_cap) * 4
            for v in range(1, 12):
                priority += np.sin(ratio * v) / (v ** 1.5 + 0.5)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.8
        elif bin_cap > item * 3.5:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 6):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
